external_knowledge:
- Influence refers to the impact factor of a journal;
- Journals are collections of various articles;
- The total number of articles refers to the count of publications in each journal.

sql:
SELECT journal_id, COUNT(publication_id) AS total_publications, AVG(impact_factor) AS average_impact_factor
FROM publications
GROUP BY journal_id;

SELECT p.title, p.published_date, j.journal_name
FROM publications p
INNER JOIN journals j ON p.journal_id = j.journal_id;

SELECT title
FROM publications
WHERE publication_id = 1;
